import React, { useState, useCallback, useMemo, memo } from 'react';
import { GRID_SIZE, CELL, SHIPS } from '../constants';
import { createEmptyBoard, canPlaceShipOnBoard, generateRandomPlacement } from '../utils/gameHelpers';
import { playSound } from '../utils/sounds';

const ShipPlacement = memo(({ onShipPlaced, locked = false }) => {
    const [selected, setSelected] = useState(0);
    const [direction, setDirection] = useState('horizontal');
    const [board, setBoard] = useState(createEmptyBoard);
    const [placed, setPlaced] = useState(new Set());
    const [placements, setPlacements] = useState([]); // {shipId,row,col,length,direction,cells}[]
    const [hovered, setHovered] = useState(null);
    const [msg, setMsg] = useState('');

    const canPlace = useCallback(
        (row, col, len, dir) => canPlaceShipOnBoard(board, row, col, len, dir),
        [board]
    );

    const preview = useMemo(() => {
        if (!hovered || placed.has(selected)) return new Set();
        const { valid, cells } = canPlace(hovered.row, hovered.col, SHIPS[selected].length, direction);
        return valid ? new Set(cells.map(c => `${c.row},${c.col}`)) : new Set();
    }, [hovered, placed, selected, direction, canPlace]);

    /** Re-sync parent with current placement state (call after any change) */
    const notifyParent = useCallback((newPlacements) => {
        onShipPlaced(newPlacements);
    }, [onShipPlaced]);

    const handleCellClick = useCallback((ri, ci) => {
        // Clicking a placed ship cell → un-place that ship
        const existing = placements.find(p => p.cells.some(c => c.row === ri && c.col === ci));
        if (existing) {
            const newPlacements = placements.filter(p => p.shipId !== existing.shipId);
            const newPlaced = new Set(placed); newPlaced.delete(existing.shipId);
            const newBoard = createEmptyBoard();
            newPlacements.forEach(p => p.cells.forEach(c => { newBoard[c.row][c.col] = CELL.SHIP; }));
            setBoard(newBoard); setPlaced(newPlaced); setPlacements(newPlacements);
            setSelected(existing.shipId);
            notifyParent(newPlacements);
            setMsg(`↩️ ${SHIPS[existing.shipId].name} removed — click to re-place`);
            return;
        }

        if (placed.has(selected)) { setMsg(`${SHIPS[selected].name} already placed — click it on the grid to move it`); return; }
        const ship = SHIPS[selected];
        const { valid, cells } = canPlace(ri, ci, ship.length, direction);
        if (!valid) { setMsg(`❌ Can't place here — ships need 1-cell gap (including corners)`); return; }
        const nb = board.map(r => [...r]);
        cells.forEach(c => { nb[c.row][c.col] = CELL.SHIP; });
        setBoard(nb);
        const ns = new Set(placed); ns.add(selected); setPlaced(ns);
        const newPlacements = [...placements, { shipId: selected, row: ri, col: ci, length: ship.length, direction, cells }];
        setPlacements(newPlacements);
        notifyParent(newPlacements);
        playSound('place');
        setMsg(`✅ ${ship.name} placed!`);
        const next = SHIPS.findIndex(s => !ns.has(s.id));
        if (next !== -1) setSelected(next);
    }, [placed, selected, direction, board, canPlace, placements, notifyParent]);

    const handleRandomize = useCallback(() => {
        const result = generateRandomPlacement();
        if (!result) return;
        // Build placements with cell positions
        const newPlacements = result.placements.map((p, i) => {
            const cells = [];
            if (p.direction === 'horizontal') {
                for (let j = 0; j < p.length; j++) cells.push({ row: p.row, col: p.col + j });
            } else {
                for (let j = 0; j < p.length; j++) cells.push({ row: p.row + j, col: p.col });
            }
            return { shipId: SHIPS[i].id, row: p.row, col: p.col, length: p.length, direction: p.direction, cells };
        });
        setBoard(result.board);
        setPlacements(newPlacements);
        setSelected(0);
        const all = new Set(SHIPS.map(s => s.id)); setPlaced(all);
        notifyParent(newPlacements);
        setMsg('🎲 Fleet randomised! Click any ship to move it.');
    }, [notifyParent]);

    const handleClear = useCallback(() => {
        setBoard(createEmptyBoard()); setPlaced(new Set()); setPlacements([]); setSelected(0); setMsg('');
        notifyParent([]);
    }, [notifyParent]);

    return (
        <div className={`space-y-3 ${locked ? 'pointer-events-none' : ''}`}>

            {/* Controls */}
            <div className={`bg-slate-800/80 rounded-xl p-3 sm:p-4 border space-y-3 transition-all ${locked ? 'border-green-600/50 opacity-60' : 'border-slate-700'}`}>

                {/* Ship selector */}
                <div className="grid grid-cols-5 gap-1.5">
                    {SHIPS.map(ship => {
                        const isDone = placed.has(ship.id);
                        const isActive = selected === ship.id && !isDone;
                        return (
                            <button
                                key={ship.id}
                                onClick={() => {
                                    if (isDone) {
                                        setMsg(`Click the ${ship.name} on the grid to move it`);
                                    } else {
                                        setSelected(ship.id); setMsg(`${ship.name} selected (${ship.length} cells)`);
                                    }
                                }}
                                className={`flex flex-col items-center justify-center p-1.5 sm:p-2 rounded-lg transition-all text-center
                  ${isDone ? 'bg-emerald-800/60 text-emerald-300 cursor-pointer hover:bg-emerald-700/60 ring-1 ring-emerald-600' :
                                        isActive ? 'bg-violet-600 text-white ring-2 ring-yellow-400 scale-105 shadow-md' :
                                            'bg-slate-700 hover:bg-slate-600 text-slate-100'}`}
                            >
                                <span className="text-base sm:text-lg">{isDone ? '✅' : ship.emoji}</span>
                                <span className="text-[0.58rem] sm:text-[0.65rem] font-semibold mt-0.5 leading-none">{ship.name}</span>
                                <span className="text-[0.5rem] sm:text-[0.6rem] text-slate-300 mt-0.5">{ship.length}×</span>
                            </button>
                        );
                    })}
                </div>

                {/* Direction + action buttons */}
                <div className="flex flex-wrap gap-2 items-center justify-between">
                    <div className="flex rounded-lg overflow-hidden border border-slate-600 bg-slate-700">
                        {['horizontal', 'vertical'].map(d => (
                            <button
                                key={d}
                                onClick={() => setDirection(d)}
                                className={`px-3 sm:px-4 py-1.5 text-xs sm:text-sm font-semibold transition ${direction === d ? 'bg-blue-600 text-white' : 'text-slate-300 hover:bg-slate-600'}`}
                            >
                                {d === 'horizontal' ? '➡ Horiz' : '⬇ Vert'}
                            </button>
                        ))}
                    </div>
                    <div className="flex gap-2">
                        <button onClick={handleRandomize} disabled={locked} className="px-3 py-1.5 bg-amber-500 hover:bg-amber-400 disabled:opacity-40 disabled:cursor-not-allowed text-white text-xs sm:text-sm font-bold rounded-lg transition">
                            🎲 Random
                        </button>
                        <button onClick={handleClear} disabled={placed.size === 0 || locked} className="px-3 py-1.5 bg-slate-600 hover:bg-slate-500 disabled:opacity-40 disabled:cursor-not-allowed text-white text-xs sm:text-sm font-semibold rounded-lg transition">
                            🗑 Clear
                        </button>
                    </div>
                </div>

                {msg && (
                    <p className={`text-xs sm:text-sm text-center rounded-lg px-3 py-1.5 font-medium ${msg.startsWith('❌') ? 'bg-red-900/40 text-red-300' :
                        msg.startsWith('✅') || msg.startsWith('🎲') || msg.startsWith('↩️') ? 'bg-emerald-900/40 text-emerald-300' :
                            'bg-slate-700/50 text-slate-300'
                        }`}>{msg}</p>
                )}

                {/* Progress */}
                <div>
                    <div className="flex justify-between text-[0.65rem] text-slate-400 mb-1">
                        <span>{placed.size}/5 placed</span>
                        <span>{5 - placed.size} remaining</span>
                    </div>
                    <div className="w-full bg-slate-700 rounded-full h-1.5">
                        <div className="bg-gradient-to-r from-emerald-500 to-green-400 h-1.5 rounded-full transition-all" style={{ width: `${(placed.size / 5) * 100}%` }} />
                    </div>
                </div>
            </div>

            {/* Placement board */}
            <div className={`bg-slate-800/80 rounded-xl p-3 sm:p-4 border transition-all ${locked ? 'border-green-600/50' : 'border-slate-700'}`}>
                {locked
                    ? <p className="text-green-300 text-[0.65rem] mb-2 text-center font-semibold">✅ Fleet locked in — click ↩️ Unready above to make changes</p>
                    : <p className="text-slate-400 text-[0.65rem] mb-2 text-center">Hover to preview · Click water to place · <span className="text-red-300">Click a ship to move it</span></p>
                }
                <div
                    className="grid w-full"
                    style={{ gridTemplateColumns: 'clamp(14px,3.5vw,26px) repeat(10, 1fr)', gridTemplateRows: 'clamp(14px,3.5vw,26px) repeat(10, 1fr)', aspectRatio: '11/11' }}
                >
                    <div />
                    {Array.from({ length: GRID_SIZE }).map((_, c) => (
                        <div key={c} className="flex items-center justify-center text-blue-300 font-bold text-[clamp(0.45rem,1.1vw,0.65rem)]">
                            {String.fromCharCode(65 + c)}
                        </div>
                    ))}
                    {board.map((row, ri) => (
                        <React.Fragment key={ri}>
                            <div className="flex items-center justify-center text-blue-300 font-bold text-[clamp(0.45rem,1.1vw,0.65rem)]">
                                {ri + 1}
                            </div>
                            {row.map((cell, ci) => {
                                const isShip = cell === CELL.SHIP;
                                const isPrev = !locked && preview.has(`${ri},${ci}`);
                                return (
                                    <button
                                        key={ci}
                                        type="button"
                                        className={`aspect-square w-full border border-slate-800/40 transition-all duration-75
                      ${isShip ? (locked ? 'bg-emerald-500 cursor-default' : 'bg-emerald-500 hover:bg-red-400 cursor-pointer') :
                                                isPrev ? 'bg-yellow-400 hover:bg-yellow-300 cursor-crosshair scale-105 z-10' :
                                                    locked ? 'bg-blue-500/70 cursor-default' :
                                                        'bg-blue-500/70 hover:bg-blue-400 cursor-crosshair'}
                    `}
                                        title={!locked && isShip ? 'Click to move this ship' : ''}
                                        onClick={() => !locked && handleCellClick(ri, ci)}
                                        onMouseEnter={() => !locked && setHovered({ row: ri, col: ci })}
                                        onMouseLeave={() => !locked && setHovered(null)}
                                    />
                                );
                            })}
                        </React.Fragment>
                    ))}
                </div>
            </div>
        </div>
    );
});

ShipPlacement.displayName = 'ShipPlacement';

export default ShipPlacement;
